&quot;) ## TC(5) numerical = 120 q_vals &lt;- seq(0, 10, by = 0.1) df_tc &lt;- data.frame(q = q_vals, MC = MC_fn(q_vals), TC = TC_fn(q_vals)) ggplot(df_tc, aes(x = q)) + geom_line(aes(y = MC, color = &quot;MC&quot;), size = 1) + geom_line(aes(y = TC, color = &quot;TC&quot;), size = 1) + labs(title = &quot;Marginal Cost and Total Cost&quot;, x = &quot;Quantity&quot;, y = &quot;Cost&quot;, color = &quot;Curve&quot;) + theme_minimal()
